import { useEffect, useState } from "react"
function Crypto() {
  let [cryptodata, changecryptodata] = useState([])
  useEffect(() => {
    async function fetchcoins() {
      let fetched = await fetch("https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&ids=bitcoin,ethereum,binancecoin,ripple,solana,staked-ether,tron,dogecoin,monero&sparkline=true")
      let fetchedjson = await fetched.json()
      changecryptodata(fetchedjson)
    }
    fetchcoins()
  }, [])
  useEffect(() => {
    console.log(cryptodata[0].sparkline_in_7d)
  }, [cryptodata])
